import React, { useState, useEffect, useRef } from 'react';
import { getContacts, uploadFiles, deleteChat } from '../services/api';
import './Sidebar.css';

export default function Sidebar({ activePhone, onSelect }) {
  const [contacts, setContacts] = useState([]);
  const [search, setSearch] = useState('');
  const [uploading, setUploading] = useState(false);
  const [progress, setProgress] = useState(0);
  const [uploadMsg, setUploadMsg] = useState('');
  const fileRef = useRef();

  const fetchContacts = async (q = '') => {
    try {
      const { data } = await getContacts(q);
      setContacts(data);
    } catch (e) {
      console.error(e);
    }
  };

  useEffect(() => { fetchContacts(); }, []);

  useEffect(() => {
    const t = setTimeout(() => fetchContacts(search), 300);
    return () => clearTimeout(t);
  }, [search]);

  const handleUpload = async (e) => {
    const files = Array.from(e.target.files);
    if (!files.length) return;
    const form = new FormData();
    files.forEach((f) => form.append('files', f));
    setUploading(true);
    setProgress(0);
    setUploadMsg('');
    try {
      const { data } = await uploadFiles(form, setProgress);
      const created = data.results.filter((r) => r.status === 'created').length;
      const updated = data.results.filter((r) => r.status === 'updated').length;
      setUploadMsg(`✓ ${created} new, ${updated} updated${data.errors.length ? `, ${data.errors.length} failed` : ''}`);
      fetchContacts(search);
    } catch (err) {
      setUploadMsg('Upload failed. Check backend.');
    } finally {
      setUploading(false);
      e.target.value = '';
    }
  };

  const handleDelete = async (e, phone) => {
    e.stopPropagation();
    if (!window.confirm(`Delete chat for +${phone}?`)) return;
    await deleteChat(phone);
    fetchContacts(search);
  };

  return (
    <div className="sidebar">
      <div className="sidebar-header">
        <div className="avatar header-avatar">W</div>
        <span className="header-title">WATI Chats</span>
        <label className="upload-icon-btn" title="Upload .txt files">
          <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
            <path d="M21 15v4a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2v-4"/>
            <polyline points="17 8 12 3 7 8"/>
            <line x1="12" y1="3" x2="12" y2="15"/>
          </svg>
          <input ref={fileRef} type="file" multiple accept=".txt" style={{ display: 'none' }} onChange={handleUpload} />
        </label>
      </div>

      {uploading && (
        <div className="upload-progress">
          <div className="progress-bar" style={{ width: `${progress}%` }} />
          <span>Uploading... {progress}%</span>
        </div>
      )}
      {uploadMsg && <div className="upload-msg">{uploadMsg}</div>}

      <div className="search-box">
        <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="#999" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
          <circle cx="11" cy="11" r="8"/><line x1="21" y1="21" x2="16.65" y2="16.65"/>
        </svg>
        <input
          type="text"
          placeholder="Search by phone..."
          value={search}
          onChange={(e) => setSearch(e.target.value)}
        />
      </div>

      <div className="contact-list">
        {contacts.length === 0 ? (
          <div className="empty-list">
            {search ? 'No results found' : 'Upload .txt files to begin'}
          </div>
        ) : (
          contacts.map((c) => (
            <div
              key={c.phone}
              className={`contact-item${activePhone === c.phone ? ' active' : ''}`}
              onClick={() => onSelect(c.phone)}
            >
              <div className="avatar">{c.phone.slice(-2)}</div>
              <div className="contact-info">
                <div className="contact-name">+{c.phone}</div>
                <div className="contact-preview">{c.lastMessage || 'No messages'}</div>
              </div>
              <div className="contact-right">
                <div className="msg-count">{c.messageCount}</div>
                <button className="del-btn" onClick={(e) => handleDelete(e, c.phone)} title="Delete">✕</button>
              </div>
            </div>
          ))
        )}
      </div>
    </div>
  );
}
